<template>
    <div>
        <loader :is-visible="isLoading"></loader>
        <section id="main-content" class="main-content">
            <div class="col-md-8 my-4 mx-auto" v-if="isShowListButton">
                <div class="stepper-container">
                    <!-- Upload -->
                    <button
                        :class="(isShowExcelColumnBind || isExcelDataBind || isShowErrorFields || isImportedSuccess) ? 'step completed' : (isShowUploadExcelLead ? 'step active' : 'step')"
                        @click="goToUploadStep" type="button"
                        style="background:none; border:none; padding:0; cursor:pointer;">
                        <div class="circle"
                            v-if="(isShowExcelColumnBind || isExcelDataBind || isShowErrorFields || isImportedSuccess)">
                            <em class="fa fa-check"></em>
                        </div>
                        <div class="circle" v-else>1</div>
                        <div class="label">{{ $t('Upload') }}</div>
                    </button>
                    <!-- Step 2: Mapping -->
                    <div class="line"></div>
                    <button
                        :class="(isShowErrorFields || isExcelDataBind || isImportedSuccess) ? 'step completed' : (isShowExcelColumnBind ? 'step active' : 'step')"
                        @click="goToMappingStep" type="button"
                        style="background:none; border:none; padding:0; cursor:pointer;">
                        <div class="circle" v-if="(isShowErrorFields || isExcelDataBind || isImportedSuccess)">
                            <em class="fa fa-check"></em>
                        </div>
                        <div class="circle" v-else>2</div>
                        <div class="label">{{ $t('Mapping') }}</div>
                    </button>
                    <!-- Step 3: Validation -->
                    <div class="line"></div>
                    <button
                        :class="(isExcelDataBind || isImportedSuccess) ? 'step completed' : (isShowErrorFields ? 'step active' : 'step')"
                        @click="goToValidationstep" type="button"
                        style="background:none; border:none; padding:0; cursor:pointer;">
                        <div class="circle" v-if="(isExcelDataBind || isImportedSuccess)">
                            <em class="fa fa-check"></em>
                        </div>
                        <div class="circle" v-else>3</div>
                        <div class="label">{{ $t('Validation') }}</div>
                    </button>
                    <!-- Step 4: Preview -->
                    <div class="line"></div>
                    <button :class="isImportedSuccess ? 'step completed' : (isExcelDataBind ? 'step active' : 'step')"
                        @click="goToPreviewstep" type="button"
                        style="background:none; border:none; padding:0; cursor:pointer;">
                        <div class="circle" v-if="isImportedSuccess">
                            <em class="fa fa-check"></em>
                        </div>
                        <div class="circle" v-else>4</div>
                        <div class="label">{{ $t('Preview') }}</div>
                    </button>
                    <!-- Import -->
                    <div class="line"></div>
                    <div :class="{ 'step': true, 'completed': isImportedSuccess }">
                        <div class="circle">5</div>
                        <div class="label">{{ $t('Import') }}</div>
                    </div>
                </div>
            </div>

            <div class="row">
                <div class="col-md-12 padding-t_8">
                    <div class="theme-primary partition-full">
                        <span class="p-name text-white">{{ $t('ImportLeads') }}</span>
                        <span class="p-actions float-right">
                            <a v-if="!isShowListButton && !isShowExcelColumnBind && !isExcelDataBind && !isShowErrorFields && !isImportedSuccess"
                                :title="$t('ImportLeads')" href="javascript:;" class="p-action-btn text-white"
                                @click="hideBatchList">
                                <em class="fa fa fa-plus"></em>
                                <br /><span>{{ $t('ImportLeads') }}</span>
                            </a>
                            <a v-if="isShowListButton && !isShowExcelColumnBind && !isExcelDataBind && !isShowErrorFields && !isImportedSuccess"
                                :title="$t('BatchList')" href="javascript:;" class="p-action-btn text-white"
                                @click="hideBatchList">
                                <em class="fa fa fa-list"></em>
                                <br /><span>{{ $t('BatchList') }}</span>
                            </a>
                            <RouterLink to="/CRM/Index" id="btnbacktolist" :title="$t('BacktoList')"
                                class="p-action-btn text-white float-right">
                                <em class="fa fa-angle-double-left pr-2"></em><br />{{ $t('BacktoList') }}
                            </RouterLink>
                        </span>
                    </div>
                </div>
            </div>
        </section>

        <UploadExcelLeads ref="uploadLeads" v-if="isShowUploadExcelLead" @ImportData="importFile"></UploadExcelLeads>
        <ExcelColumnBind v-if="isShowExcelColumnBind" :excelColumns="excelColumns" :tableColumns="tableColumns"
            @checkValidation="checkValidation"></ExcelColumnBind>
        <validationFieldLIst v-if="isShowErrorFields" :batchId="batchId" subModuleCode="CRM_LEADS" callFrom="preview"
            @next="isShowErrorFields = false, isExcelDataBind = true"
            @back="isShowErrorFields = false, isShowExcelColumnBind = true"></validationFieldLIst>
        <ExcelDataBind v-if="isExcelDataBind" :batchId="batchId" @next="SaveExcelData" :IsAction="IsAction"
            @backToValidation="isExcelDataBind = false, isShowErrorFields = true"></ExcelDataBind>

        <div v-if="isImportedSuccess">
            <h3 class="text-success text-center mt-4">Leads imported successfully.</h3>
            <div class="col-12 mt-3 p-0">
                <div class="row flex-row-reverse">
                    <div class="col-lg-6 text-right">
                        <RouterLink to="/CRM/Index" :title="$t('BacktoList')"
                            :class="{ 'btn btn-secondary my-2 mr-2': true }">
                            <em class="fa fa-angle-double-left mr-2" aria-hidden="true"></em> {{ $t('BacktoList') }}
                        </RouterLink>
                    </div>
                </div>
            </div>
        </div>

    </div>
</template>
<script>
import DataService from '../../services/DataService';
import * as XLSX from 'xlsx';
import UploadExcelLeads from './UploadExcelLeads.vue';
import ExcelColumnBind from './ExcelColumnBind.vue';
import validationFieldLIst from './validationFieldLIst.vue';
import ExcelDataBind from './ExcelDataBind.vue';

export default {
    components: {
        UploadExcelLeads,
        ExcelColumnBind,
        ExcelDataBind,
        validationFieldLIst
    },
    data: function () {
        return {
            isLoading: false,
            isShowUploadExcelLead: true,
            isShowExcelColumnBind: false,
            isExcelDataBind: false,
            excelRowCount: null,
            file: null,
            isUploadedExcel: false,
            showSaveButton: false,
            tableColumn: '',
            excelColumn: '',
            rows: [],
            rownumber: 1002,
            isLoading: false,
            MandatoryString: '',
            excelColumns: [],
            tableColumns: [],
            allrequiredcol: "",
            filepath: null,
            batchId: '',
            noRecordFound: true,
            isActiveStep: 1,
            isFistStep: false,
            isSecondStep: false,
            ExcelColumndata: [],
            IsAction: '',
            IsUpdateField: '',
            isShowErrorFields: false,
            isImportedSuccess: false,
            isShowListButton: false,
        }
    },
    methods: {

        goToUploadStep() {
            this.isShowUploadExcelLead = true;
            this.isShowExcelColumnBind = false;
            this.isExcelDataBind = false;
            this.isShowErrorFields = false;
            this.isImportedSuccess = false;
        },

        goToMappingStep() {
            if (this.excelColumns.length && this.tableColumns.length) {
                this.isShowUploadExcelLead = false;
                this.isShowExcelColumnBind = true;
                this.isExcelDataBind = false;
                this.isShowErrorFields = false;
                this.isImportedSuccess = false;
            }
        },

        goToValidationstep() {
            if (this.batchId) {
                this.isShowUploadExcelLead = false;
                this.isShowExcelColumnBind = false;
                this.isExcelDataBind = false;
                this.isShowErrorFields = true;
                this.isImportedSuccess = false;

            }
        },
        goToPreviewstep() {
            if (this.batchId) {
                this.isShowUploadExcelLead = false;
                this.isShowExcelColumnBind = false;
                this.isExcelDataBind = true;
                this.isShowErrorFields = false;
                this.isImportedSuccess = false;
            }
        },

        importFile(selectedFile, file, excelFileName, event, Field) {
            var vm = this;
            vm.IsAction = event;
            vm.IsUpdateField = Field;
            const reader = new FileReader();
            reader.onload = (e) => {
                const data = e.target.result;
                const workbook = XLSX.read(data, { type: 'binary' });
                // Assuming the first sheet contains the data
                const firstSheet = workbook.Sheets[workbook.SheetNames[0]];
                const jsonData = XLSX.utils.sheet_to_json(firstSheet, { header: 1 }); // Extract data as 2D array

                const filteredData = jsonData.filter(row => row.length > 0);
                const validLength = filteredData.length;

                // Get the row count (excluding the header row)
                vm.excelRowCount = validLength - 1; // Subtract 1 for the header row
                let greeting = `Excel File Read Successfully! A total of ${vm.excelRowCount} records detected. Click "OK" to proceed with the import`;

                vm.confirmR(greeting, true, vm.$t("Confirm"),
                    function () {

                        vm.UploadLeadFile(file, excelFileName);
                    });
            };
            reader.readAsBinaryString(selectedFile); // Read file as binary string
        },
        UploadLeadFile(file, excelFileName) {
            var vm = this;
            vm.isLoading = true;
            const formdata = new FormData();
            formdata.append('file', file);

            if (file) {
                DataService.ImportContactsPost(formdata).then((response) => {
                    const data = response.data;
                    if (data.Status === 0) {
                        vm.filepath = data.Msg;
                        setTimeout(() => vm.loadExcelHeader(data.Msg, excelFileName), 1000);
                        setTimeout(() => vm.loadTableHeader(), 2000);
                        vm.isLoading = false;
                        vm.isUploadedExcel = true;
                    } else {
                        vm.isLoading = false;
                        vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", vm.$t('Alert'));
                    }
                });
            } else {
                vm.isLoading = false;
                vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", vm.$t('Alert'));
            }
        },
        loadExcelHeader(filepath, excelFileName) {
            var vm = this;
            vm.isLoading = true;
            const param = `filepath=${filepath}&excelFileName=${excelFileName}`;
            DataService.GetContactExcelColumn(param).then((response) => {
                vm.isLoading = false;
                if (response.data.length > 0) {
                    vm.excelColumns = response.data;
                    vm.batchId = response.data[0].batch_id;

                    vm.excelColumns.forEach((Value, Index) => {

                        let myobj = {
                            value: Index + 1,
                            name: Value.column_Name,
                            excelColumn: ''
                        }
                        vm.ExcelColumndata.push(myobj);
                    })
                    vm.$set(this, 'excelColumns', response.data);
                } else {
                    vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", vm.$t('Alert'));
                }
            }).catch(() => {
                vm.isLoading = false;
                vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", vm.$t('Alert'));
            });
        },
        loadTableHeader() {
            var vm = this;
            vm.isLoading = true;
            const param = 'submodule=CRM_LEADS&batchid=""';
            DataService.GetContactTableColumn(param).then((response) => {
                vm.isLoading = false;
                if (response.data && response.data.length > 0) {
                    vm.tableColumns = response.data.sort((a, b) => (a.is_Required ? -1 : 1));
                    vm.$set(this, 'tableColumns', response.data);
                    vm.isShowUploadExcelLead = false;
                    vm.isShowExcelColumnBind = true;
                } else {
                    vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", vm.$t('Alert'));
                }
            }).catch(() => {
                vm.isLoading = false;
                vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", vm.$t('Alert'));
            });
        },
        async checkValidation() {
            var vm = this;
            vm.isShowExcelColumnBind = false;
            vm.isShowErrorFields = true;
        },
        SaveExcelData() {
            var vueObj = this;
            vueObj.isLoading = true;
            var param = `BatchId=${vueObj.batchId}&ModuleCode=CRM&SubModuleCode=CRM_LEADS&IsAction=${vueObj.IsAction}&UpdateField=${vueObj.IsUpdateField} `;
            DataService.SaveImportleadData(param).then(function (response) {
                if (response.data == "ADD DATA SUCCESSFULLY!") {
                    vueObj.isExcelDataBind = false;
                    vueObj.isImportedSuccess = true;
                    vueObj.isLoading = false;
                }
                else {
                    vueObj.ShowAlert(vueObj.$t('AddedError', [vueObj.$t('Lead')]), 'danger', true, vueObj.$t("Alert"));
                }
                vueObj.isLoading = false;
            });
        },
        hideBatchList() {
            var vm = this;
            const childComponent = vm.$refs.uploadLeads;
            if (childComponent) {
                if (!vm.isShowListButton) {
                    childComponent.isShowBatchList = false;
                    vm.isShowListButton = true;
                }
                else {
                    childComponent.isShowBatchList = true;
                    vm.isShowListButton = false;
                }
            }
        }
    }
};
</script>

<style>
.stepper-container {
    display: flex;
    align-items: center;
    justify-content: center;
    font-family: Arial, sans-serif;
}

.step {
    display: flex;
    align-items: center;
    color: #555;
}

.circle {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    background-color: #fff;
    border: 1px solid #707070;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 500;
    margin-right: 8px;
    font-size: 20px;
}

.active .circle {
    background-color: #1890ff;
    border-color: #1890ff;
    color: #fff;
}

.completed .circle {
    background-color: #08b905;
    border-color: #08b905;
    color: #fff;
}

.completed .circle em {
    color: #fff;
}

.label {
    margin-right: 16px;
}

.line {
    flex: 1;
    height: 2px;
    background-color: #707070;
    margin: 0 8px;
}

.btn.btnshowstats {
    color: #fff;
    border: none;
    padding: 6px 20px;
    border-radius: 8px !important;
    cursor: pointer;

}

.btn.btnshowstats.disabled {
    background-color: #cbcbcb !important;
    color: #fff !important;
}
</style>