<template>
    <section>
        <div class="modal d-block my-popups dialog">
            <loader :is-visible="isLoading"></loader>
            <div class="modal-dialog">
                <div class="modal-content">
                    <div class="modal-header">
                        <slot name="headerForModal">
                            <h5 class="modal-title">{{ $t('Error') }} {{ $t('Details') }} ({{ customFieldName }})</h5>
                        </slot>
                        <button type="button" v-on:click="$emit('close')" href="javascript:;" class="close">
                            <em class="fa fa-times"></em>
                        </button>
                    </div>
                    <div class="modal-body">
                        <div class="row form-head">
                            <span class="user-guide">
                                <a class="ancuserguide" data-toggle="collapse" href="javascript:;" role="button"
                                    aria-expanded="false" aria-controls="collapseExample">
                                    {{ $t('UserGuide') }}
                                </a>
                                <div id="collapseReply" class="divancuserguide collapse">
                                    <div id="scrollbarreplyuserguide" class="custom-scrollbar-js">
                                        <div class="con" v-html="$t('Lead_Fix_Error_Guide')"></div>
                                    </div>
                                </div>
                            </span>
                        </div>

                        <div class="row">
                            <div class="col-lg-12 mb-3">
                                <div class="heading-border mt-2">
                                    <h5 class="h5"><span>{{ $t('TotalRecordsProcessed') }}: {{ totalProcessedRecords }}
                                        </span></h5>
                                </div>
                            </div>
                        </div>
                        <tg-list :isShowHeaderText="false" :IsShowAction="false" ModuleName="CRM"
                            :SubModuleCode="subModuleCode" IdentityColumn="id" :listType="['List']" :ListData="ListData"
                            ref="tgList" :HeaderData="Headers" :HeaderButtons="false" :TotalRecords="TotalRecords"
                            :SearchFields="leftSearchFields" :IsSearchFieldsOnTop="true" SearchPosition="top"
                            :widgets="[]" :RenderRowActionMethod="renderActions" :ListDataCallBackFunction="FetchData"
                            :LegendArray="[]" :IsFilterApplied="false" :SortExp="SortExp" :SortBy="SortBy"
                            :CurrentPageNumber="PageNumber" v-on:LeftsearchButtonClick="leftCommonSearch"
                            v-on:PagerButtonClick="pagerMethod" :NorecordfoundText="$t('NoRecordfound')"
                            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:ActionButtonClick="actionButtonClick"
                            v-on:SortdataButtonClick="sortdata" :showCheckBox="false">
                            <template v-slot:slotdata="{ data }">
                                <template v-if="data.column.COLUMN_NAME == 'correct_value'">
                                    <input type="text" v-model="data.row.correct_value" class="form-control"
                                        :class="{ 'is-invalid': !isValidFormat(data.row.correct_value).valid }" />

                                    <small
                                        v-if="data.row.correct_value !== undefined && !isValidFormat(data.row.correct_value).valid"
                                        class="text-danger">
                                        {{ isValidFormat(data.row.correct_value).message }}
                                    </small>
                                </template>


                                <template v-if="data.column.COLUMN_NAME == 'action'">
                                    <a href="javascript:;" v-on:click="fixValue(data.row)" class="btn btn-info">{{
                                        $t('Fix') }}</a>
                                </template>
                            </template>
                        </tg-list>
                    </div>
                </div>
            </div>
        </div>
    </section>
</template>

<script>
import DataService from '../../../services/DataService';

export default {
    props: {
        batchId: {
            type: String
        },
        customFieldId: {
            type: Number
        },
        customFieldName: {
            type: String
        },
        totalProcessedRecords: {
            type: String
        },
        subModuleCode: {
            type: String
        }
    },
    data() {
        return {

            //Custom validation
            validationMessages: {
                required: "This field is required.",
                invalidEmail: "Invalid email format."
            },
            isLoading: false,
            ListData: [],
            duplicateRecoreds: [],
            TotalRecords: 0,
            Headers: [
                {
                    COLUMN_NAME: 'name',
                    DATA_TYPE: "string",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('Name'),
                    DISPLAY_ORDER: 1,
                },
                {
                    COLUMN_NAME: 'current_value',
                    DATA_TYPE: "string",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('CurrentValue'),
                    DISPLAY_ORDER: 2,
                },
                {
                    COLUMN_NAME: 'preview_information',
                    DATA_TYPE: "string",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('PreviewInformation'),
                    DISPLAY_ORDER: 4,
                },
                {
                    COLUMN_NAME: 'correct_value',
                    DATA_TYPE: "string",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('CorrectValue'),
                    DISPLAY_ORDER: 5,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    COLUMN_NAME: 'action',
                    DATA_TYPE: "string",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('Action'),
                    DISPLAY_ORDER: 6,
                    settings: {
                        isInSlot: true
                    }
                },
            ],
            leftSearchFields: [{
                fieldName: 'Search',
                fieldType: "text",
                fieldSearchConditionName: [''],
                paramName: "search",
                isSearch: true,
                value: "",
                listOptions: []
            }],
            SortExp: '',
            SortBy: '',
            PageNumber: 1,
            searchCondition: '',
            PageSize: 10,

        }
    },
    created() {
        this.FetchData();
    },
    methods: {
        //Check valid email format
        isValidFormat(value) {
            if (!value || value === "") {
                return { valid: false, message: this.validationMessages.required };
            }
            //   const regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            //   if (!regex.test(value)) {
            //     return { valid: false, message: this.validationMessages.invalidEmail };
            //   }
            return { valid: true, message: "" };
        },
        FetchData() {
            debugger
            var vm = this;
            vm.isLoading = true;
            let params = `batchId=${vm.batchId}&customFieldId=${vm.customFieldId}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&pageNum=${vm.PageNumber}&pageSize=${vm.PageSize}&searchCondition=${vm.searchCondition}`;
            DataService.GetImportedRecordsErrorWithPreviewInfo(params).then((response) => {
                if (response.data && response.data.data) {
                    const allRecords = response.data.data;
                    const seen = new Set();
                    const uniqueRecords = [];

                    allRecords.forEach(record => {
                        const key = `${record.row_id}_${JSON.stringify(record)}`;
                        if (!seen.has(key)) {
                            seen.add(key);
                            uniqueRecords.push(record);
                        }
                    });

                    vm.ListData = uniqueRecords;
                    vm.TotalRecords = response.data.total_records || uniqueRecords.length;
                } else {
                    vm.TotalRecords = 0;
                    vm.ListData = [];
                }

                vm.isLoading = false;
            }).catch((error) => {
                vm.isLoading = false;
                console.error(error);
            });
        },
        sortdata: function (s) {
            debugger
            var SortDir = "sort tb_headerSortDown";
            this.SortBy = s;
            if (s === this.SortBy) {
                if (this.SortExp == "") {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
                else if (this.SortExp == "ASC") {
                    this.SortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                }
                else {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }
            this.FetchData();
            $("#" + s + '  span:first-child').attr("class", SortDir);
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            if (value.searchCondition) {
                let str = value.searchConditionJson;
                let result = str.split('=')[1];
                this.searchCondition = result;
            }
            else {
                this.searchCondition = "";
            }
            this.FetchData();
        },
        renderActions: function (row) {
        },
        commonHeaderButtonClick() { },
        actionButtonClick() { },
        async fixValue(row) {
            //Check valition 
            const validation = this.isValidFormat(row.correct_value);
            if (!validation.valid) {
                return;
            }
            var vm = this;
            vm.isLoading = true;
            var obj = {
                data: [{ "row_id": row.row_id, "correct_value": row.correct_value }],
                batchId: vm.batchId,
                customFieldId: vm.customFieldId
            };
            let params = JSON.stringify(obj);
            await DataService.UpdateBatchRow(params).then(async (response) => {

                if (response.data && response.data[0].Value) {
                    if (response.data[0].Value.toLowerCase() == 'success') {
                        vm.ShowAlert(vm.$t("RecordUpdatedSuccessfully"), "success", vm.$t('Alert'));
                        await vm.$parent.FetchData();
                        //await vm.FetchData();
                        vm.$emit('close');
                    }
                    else if (response.data[0].Value.toLowerCase() == 'record_not_exists') {
                        vm.ShowAlert(vm.$t("Lead_Owner_Not_Exist"), "warning", vm.$t('Alert'));
                    }
                    else {
                        vm.ShowAlert(vm.$t('ErrorMessage', [vm.$t('Update')]), "failure", true, vm.$t("Alert"));
                    }
                } else {
                    vm.ShowAlert(vm.$t('ErrorMessage', [vm.$t('Update')]), "failure", true, vm.$t("Alert"));
                }
                vm.isLoading = false;
            }).catch((error) => {
                vm.isLoading = false;
                console.error(error);
            });
        }
    }
}
</script>

<style>
.listing .table .fixed-cell-padding {
    padding: 10px 8px !important;
}
</style>